// TypeScript interfaces and types for drainage pipe calculations

export interface DrainagePipeLookupRow {
  pipeDia: number;        // Pipe diameter (m)
  pipeOD: number;         // Pipe outer diameter (m)
  invertD: number;        // Invert depth (m)
  bedThck: number;        // Bedding thickness (m)
  trenchD: number;        // Trench depth (m)
  trenchW: number;        // Trench width (m)
  surround: number;       // Surround parameter
  surroundVol: number;    // Surround volume (m³/m)
  trenchVol: number;      // Trench volume (m³/m)
  surroundVolCalced: number; // Calculated surround volume (m³/m)
  backfillVol: number;    // Backfill volume (m³/m)
  spoilVol: number;       // Spoil volume (m³/m)
  output5t: number;       // 5-tonne excavator output (m/shift)
  output14t: number;      // 14-tonne excavator output (m/shift)
  output21t: number;      // 21-tonne excavator output (m/shift)
  output30t: number;      // 30-tonne excavator output (m/shift)
  output40: number;       // 40-tonne excavator output (m/shift)
  output50: number;       // 50-tonne excavator output (m/shift)
  output60: number;       // 60-tonne excavator output (m/shift)
}

export type ExcavatorType = '5t' | '14t' | '21t' | '30t' | '40t' | '50t' | '60t';

