// Helper function to find lookup row by diameter and depth
export function findLookupRow(diameter: number, depth: number): DrainagePipeLookupRow | undefined {
  return DRAINAGE_PIPE_DATA.find(row => 
    Math.abs(row.pipeDia - diameter) < 0.01 && 
    Math.abs(row.invertD - depth) < 0.01
  );
}

// Helper function to get excavator output rate
export function getExcavatorOutput(row: DrainagePipeLookupRow, excavatorType: ExcavatorType): number {
  switch (excavatorType) {
    case '5t': return row.output5t;
    case '14t': return row.output14t;
    case '21t': return row.output21t;
    case '30t': return row.output30t;
    case '40t': return row.output40;
    case '50t': return row.output50;
    case '60t': return row.output60;
    default: return 0;
  }
}

// Helper function to get plant daily hire rates
export function getPlantDailyRate(excavatorType: ExcavatorType): number {
  const rates: Record<ExcavatorType, number> = {
    '5t': 200,
    '14t': 250,
    '21t': 300,
    '30t': 350,
    '40t': 380,
    '50t': 410,
    '60t': 440
  };
  return rates[excavatorType];
}

// Main calculation function
export interface DrainageCostParams {
  diameter: number;          // Pipe diameter in meters
  depth: number;             // Invert depth in meters
  length: number;            // Length in meters
  excavatorType: ExcavatorType;
  pipeCostPerMetre: number;  // £/m for pipe material
  gravelCostPerTonne?: number; // £/t (default: £15/t)
  disposalCostPerTonne?: number; // £/t (default: £20/t)
}

export interface DrainageCostBreakdown {
  labourCost: number;
  materialCost: number;
  plantCost: number;
  totalCost: number;
  costPerMetre: number;
  hoursRequired: number;
  outputRate: number;
}

export function calculateDrainageCost(params: DrainageCostParams): DrainageCostBreakdown | null {
  const {
    diameter,
    depth,
    length,
    excavatorType,
    pipeCostPerMetre,
    gravelCostPerTonne = 15,
    disposalCostPerTonne = 20
  } = params;

  // Find lookup row
  const row = findLookupRow(diameter, depth);
  if (!row) {
    return null;
  }

  // Get excavator output rate (m/shift)
  const outputMetresPerShift = getExcavatorOutput(row, excavatorType);
  if (outputMetresPerShift === 0) {
    return null; // Excavator not suitable for this configuration
  }

  // Calculate hours per metre (8-hour shift, capped at 50 m/shift max)
  const cappedOutput = Math.min(outputMetresPerShift, 50);
  const hoursPerMetre = 8 / cappedOutput;
  const totalHours = hoursPerMetre * length;

  // Labour cost: £95/hr (1 ganger @ £35/hr + 2 labourers @ £30/hr each)
  const labourRatePerHour = 95;
  const labourCost = labourRatePerHour * totalHours;

  // Material costs
  const pipeCost = pipeCostPerMetre * length;
  
  // Gravel cost (pea gravel density: 2.2 t/m³)
  const gravelVolume = row.surroundVol * length; // m³
  const gravelTonnes = gravelVolume * 2.2;
  const gravelCost = gravelTonnes * gravelCostPerTonne;
  
  // Disposal cost
  const spoilTonnes = row.spoilVol * length * 2.2; // assuming same density
  const disposalCost = spoilTonnes * disposalCostPerTonne;
  
  const materialCost = pipeCost + gravelCost + disposalCost;

  // Plant cost (daily rate × hours ÷ 8)
  const dailyPlantRate = getPlantDailyRate(excavatorType);
  const plantCost = (dailyPlantRate * totalHours) / 8;

  // Total cost
  const totalCost = labourCost + materialCost + plantCost;
  const costPerMetre = totalCost / length;

  return {
    labourCost,
    materialCost,
    plantCost,
    totalCost,
    costPerMetre,
    hoursRequired: totalHours,
    outputRate: outputMetresPerShift
  };
}